<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;use App\Services\AssetActivityService;
final class MaintenanceController{
 public function index():void{Auth::requireRole('owner','office','crew_leader');$db=Database::connection();$orders=$db->query("SELECT m.*,v.unit_number,i.name equipment_name,u.name assigned_name FROM maintenance_work_orders m LEFT JOIN vehicles v ON v.id=m.vehicle_id LEFT JOIN inventory_items i ON i.id=m.inventory_item_id LEFT JOIN users u ON u.id=m.assigned_user_id ORDER BY FIELD(m.status,'open','scheduled','in_progress','completed','cancelled'),m.scheduled_date,m.created_at DESC")->fetchAll();$vehicles=$db->query("SELECT id,unit_number FROM vehicles WHERE status<>'retired' ORDER BY unit_number")->fetchAll();$items=$db->query("SELECT id,name FROM inventory_items WHERE active=1 ORDER BY name")->fetchAll();$users=$db->query("SELECT id,name FROM users WHERE status='active' ORDER BY name")->fetchAll();View::render('portal/maintenance/index',['title'=>'Maintenance Work Orders','orders'=>$orders,'vehicles'=>$vehicles,'items'=>$items,'users'=>$users],'portal');}
 public function store():void{Auth::requireRole('owner','office','crew_leader');verify_csrf();$db=Database::connection();$n=next_number('MWO-');$db->prepare("INSERT INTO maintenance_work_orders(work_order_number,asset_type,vehicle_id,inventory_item_id,title,description,priority,status,scheduled_date,estimated_cost,odometer,assigned_user_id,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)")->execute([$n,$_POST['asset_type'],($_POST['vehicle_id']??'')?:null,($_POST['inventory_item_id']??'')?:null,trim($_POST['title']),trim($_POST['description']??''),$_POST['priority']??'normal','open',($_POST['scheduled_date']??'')?:null,($_POST['estimated_cost']??'')?:null,($_POST['odometer']??'')?:null,($_POST['assigned_user_id']??'')?:null,Auth::id()]);$id=(int)$db->lastInsertId();AuditService::log('maintenance.created','maintenance_work_order',$id);$assetId=(int)(($_POST['asset_type']??'')==='vehicle'?($_POST['vehicle_id']??0):($_POST['inventory_item_id']??0));AssetActivityService::record($_POST['asset_type'],$assetId,'maintenance_created','Maintenance work order '.$n.' created',['work_order_id'=>$id,'priority'=>$_POST['priority']??'normal'],Auth::id());flash('success','Maintenance work order created.');redirect('/portal/maintenance');}
 public function update(string $id):void{Auth::requireRole('owner','office','crew_leader');verify_csrf();$completed=($_POST['status']??'')==='completed'?date('Y-m-d'):null;Database::connection()->prepare('UPDATE maintenance_work_orders SET status=?,priority=?,scheduled_date=?,completed_date=?,actual_cost=?,assigned_user_id=? WHERE id=?')->execute([$_POST['status'],$_POST['priority'],($_POST['scheduled_date']??'')?:null,$completed,($_POST['actual_cost']??'')?:null,($_POST['assigned_user_id']??'')?:null,(int)$id]);$db=Database::connection();$q=$db->prepare('SELECT * FROM maintenance_work_orders WHERE id=?');$q->execute([(int)$id]);$order=$q->fetch();AuditService::log('maintenance.updated','maintenance_work_order',(int)$id);if($order){$assetId=(int)($order['asset_type']==='vehicle'?$order['vehicle_id']:$order['inventory_item_id']);AssetActivityService::record($order['asset_type'],$assetId,'maintenance_'.($_POST['status']??'updated'),'Maintenance work order '.$order['work_order_number'].' updated',['work_order_id'=>(int)$id,'status'=>$_POST['status']??''],Auth::id());}flash('success','Work order updated.');redirect('/portal/maintenance');}
}
